      ? `${owners[0]} recovery review by 16:00`
      : "Continue standard monitoring.";
    const title = doc.request?.title || "Strategic account rescue";

    await client.query("DELETE FROM workflow_state WHERE account_id = $1", [accountId]);
    await client.query("DELETE FROM owner_tasks WHERE account_id = $1", [accountId]);
    await client.query("DELETE FROM customer_messages WHERE account_id = $1", [accountId]);
    await client.query("DELETE FROM audit_events WHERE account_id = $1", [accountId]);

    await client.query(
      "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
      [requestId, accountId, title, status, nextStep, riskSummary]
    );

    const dueAt = new Date("2026-06-18T16:00:00.000Z");
    for (const owner of owners) {
      await client.query(
        "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
        [requestId, accountId, owner, `${owner} account recovery review`, dueAt, "open"]
      );
    }

    if (qualifying) {
      const body = `We are proactively reaching out regarding your account. Our team has identified the following concerns requiring immediate attention: ${signals.join(", ")}. A dedicated recovery team has been assembled and is working to address each issue. We are committed to resolving these matters promptly and will provide regular updates throughout this process.`;
      await client.query(
        "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
        [requestId, accountId, body]
      );
    }

    const event = qualifying
      ? `Account escalation initiated with ${signals.length} active risk signals. Recovery teams engaged for resolution.`
      : "Account reviewed — no escalation required. Continuing standard monitoring.";
    await client.query(
      "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
      [requestId, accountId, event, new Date(now), true]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}
